import React, { forwardRef } from 'react';
import { AnchorContextProvider } from './AnchorContext';
import { Affix } from '../affix';
import type { AnchorProps, AnchorRef } from './useAnchor';
import { useAnchor } from './useAnchor';

import './style';

export const Anchor = forwardRef<AnchorRef, AnchorProps>((props, ref) => {
  const { children } = props;
  const {
    simple,
    affix,
    showInk,
    getAnchorBodyProps,
    getAnchorInkProps,
    getAffixProps,
    activeLink,
    registerLink,
    unregisterLink,
    handleLinkClick,
    scrollToSection,
    forceUpdateActiveLink,
  } = useAnchor(props);

  React.useImperativeHandle(
    ref,
    () => ({
      scrollToSection,
      forceUpdateActiveLink,
    }),
    [scrollToSection, forceUpdateActiveLink],
  );

  const renderBody = () => (
    <div {...getAnchorBodyProps()}>
      {!simple && showInk && <div {...getAnchorInkProps()} />}
      {children}
    </div>
  );

  const renderChildren = () => {
    if (affix) {
      return <Affix {...getAffixProps()}>{renderBody()}</Affix>;
    }
    return renderBody();
  };

  return (
    <AnchorContextProvider
      value={{
        registerLink,
        unregisterLink,
        activeLink,
        handleLinkClick,
      }}
    >
      {renderChildren()}
    </AnchorContextProvider>
  );
});
if (__DEV__) {
  Anchor.displayName = 'Anchor';
}
